css:
.loader {color: var(--loader-color, #2563eb);
  --loader-secondary-color: #38bdf8;
  --loader-bg: #ffffff;
  display: inline-flex;
  gap: 5px;
  animation: l1-0 1s infinite;
}.loader:before,.loader:after {content: "";
  width: 25px;
  aspect-ratio: 1;
  box-shadow: 0 0 0 3px inset var(--loader-bg, #ffffff);
  transform-origin right;
  animation: l1-1 1s infinite;
}.loader:before {transform-origin left;
  --s:-1;
}@keyframes l1-0 {to {transform: translate(100%)}}@keyframes l1-1 {to {transform: scale(calc(var(--s,1)*90deg))}}
